sql:
SELECT tax_return_id, payment_date 
FROM tax_payments
WHERE payment_method = 'bank transfer';

SELECT tax_rate 
FROM tax_brackets 
WHERE expiration_date < date('now', '-1 year');

SELECT SUM(tax_owed) AS Total_Tax_Collected
FROM tax_returns
WHERE tax_year = 2020;

SELECT tax_year, SUM(total_income) AS total_income, SUM(tax_owed) AS total_tax_owed
FROM tax_returns
GROUP BY tax_year;

external_knowledge:
- Generation Z refers to individuals born in 1997 or later (age <= 30 in the context of the query).;
- Millennials are typically considered those born from the early 1980s to the mid-1990s (age between 31 and 45 in the context of the query).;
- Boomers are individuals born from the mid-1940s to the mid-1960s (age > 45 in the context of the query).

sql:
SELECT tax_bracket_id, SUM(total_income) AS total_earnings
FROM tax_returns
GROUP BY tax_bracket_id;

SELECT DISTINCT tax_rate
FROM tax_brackets
ORDER BY tax_rate ASC;

SELECT COUNT(*) 
FROM tax_payments 
WHERE strftime('%Y', payment_date) = '2020';

SELECT tr.tax_return_id, a.audit_status
FROM tax_returns tr
JOIN audits a ON tr.tax_return_id = a.tax_return_id;

SELECT * 
FROM tax_returns 
WHERE tax_year = 2022 AND tax_bracket_id = 1;

SELECT AVG(tax_owed) AS average_tax_owed_in_2018
FROM tax_returns
WHERE tax_year = 2018 AND tax_owed IS NOT NULL;

SELECT audit_status, COUNT(*) AS frequency
FROM audits
GROUP BY audit_status;

SELECT * 
FROM tax_brackets 
ORDER BY effective_date ASC;

SELECT name, email, DATETIME(date_of_birth) AS date_of_birth
FROM taxpayers
ORDER BY name ASC;

SELECT tax_return_id, total_income
FROM tax_returns
WHERE total_income > (SELECT AVG(total_income) FROM tax_returns);

SELECT AVG(tax_owed) AS average_tax_owed
FROM tax_returns
WHERE tax_year = 2019;
